#include <iostream>
#include <cmath>
#include <iomanip>

using namespace std;

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(nullptr);

    double x;
    int n;
    cin >> x >> n;

    double sum = 0.0;
    double term = x; // x^k, starts as x^1

    for (int k = 1; k <= n; ++k) {
        sum += sin(term);
        term *= x; // term = x^(k+1)
    }

    cout << fixed << setprecision(3) << sum << '\n';

    return 0;
}
